# Ecological system from https://www.worldscientific.com/doi/abs/10.1142/S0218127421502023
# See also https://www.biorxiv.org/content/10.1101/2021.02.03.429609v2.full
# More recent paper: https://arxiv.org/pdf/2501.19062

using Random, Plots, LinearAlgebra,  ImplicitPlots, ProjectedHypersurfaceRegions

Random.seed!(1234)

# Set up incidence variety of discriminant
@var a b x[1:3]
steady_state = [
    x[1]*(1 - x[1])*(x[1] - b) - 2*a*x[1] + a*x[2] + a*x[3], 
    x[2]*(1 - x[2])*(x[2] - b) - 2*a*x[2] + a*x[1] + a*x[3], 
    x[3]*(1 - x[3])*(x[3] - b) - 2*a*x[3] + a*x[1] + a*x[2]
]
Jac = differentiate.(steady_state, x')
detJac = det(Jac)
F = System([steady_state; detJac], variables = [a; b; x])

# Set up the projected hypersurface
h_original = ProjectedHypersurface(F, [a; b])

# Degree of the original discriminant
d_original = degree(h_original)

# Fix a center for the routing functions
C = [0.02, 0.2]

# Original routing function (without using the radical)
r_original = RoutingFunction(h_original; c=C, g = [a, b, b-0.5])
∇r_original = RoutingGradient(r_original)

# "Square up" the radical generators
p = [a, b]
